+  FWFFTW3(int n_, int m_, bool forward, bool mt, bool check) : n(n_), m(m_) {
+    //FFTW_CLEANUP();
+    FFTW_PLAN_WITH_NTHREADS(mt ? omp_get_max_threads() : 1);
+    in  = (cplx*)FFTW_MALLOC(sizeof(FFTW_COMPLEX) * n * m);
+    out = (cplx*)FFTW_MALLOC(sizeof(FFTW_COMPLEX) * n * m);
