-void x86CpuID(int32_t out[4], uint32_t eax, uint32_t ecx) {
-  uint32_t a, b, c, d;
-  __asm__ __volatile__ ("cpuid" : "=a" (a), "=b" (b), "=c" (c), "=d" (d) : "a" (eax), "c"(ecx));
