+#ifdef ENABLE_DP
+    {
+      double s[VECTLENDP];
+      int i;
+      for(i=0;i<(int)VECTLENDP;i++) {
+        s[i] = d;
+      }
+      vdouble a = vloadu_vd_p(s);
+      a = xpow(a, a);
+      vstoreu_v_p_vd(s, a);
+      if (s[0] == s[0]) return 1;
+    }
+#endif
+#ifdef ENABLE_SP
+    {
+      float s[VECTLENSP];
+      int i;
+      for(i=0;i<(int)VECTLENSP;i++) {
+        s[i] = d;
+      }
+      vfloat a = vloadu_vf_p(s);
+      a = xpowf(a, a);
+      vstoreu_v_p_vf(s, a);
+      if (s[0] == s[0]) return 1;
+    }
+#endif
+    return 0;
+  }
+}
